option.value:
:root {
    color-scheme: dark;
    --bg: #07111f;
    --bg-soft: #0d1730;
    --surface: #111d35;
    --surface-soft: #192946;
    --surface-strong: #22365b;
    --text: #edf3ff;
    --muted: #aab7d1;
    --accent: #6cb7ff;
    --accent-strong: #8c7bff;
    --accent-warm: #ff7ca8;
    --accent-teal: #4ad6c3;
    --border: #31486f;
    --border-soft: rgba(124, 160, 255, 0.18);
    --focus: #9fd0ff;
    --shadow-soft: 0 10px 30px rgba(2, 8, 20, 0.28);
    --shadow-card: 0 14px 34px rgba(4, 10, 24, 0.3);
    font-family: Inter, Segoe UI, Roboto, Arial, sans-serif;
    font-size: 15px;
    line-height: 1.4;
    font-weight: 400;
}

* {
    box-sizing: border-box;
}

body {
    margin: 0;
    min-height: 100vh;
    color: var(--text);
    background:
        radial-gradient(circle at top left, rgba(108, 183, 255, 0.18), transparent 28%),
        radial-gradient(circle at top right, rgba(140, 123, 255, 0.16), transparent 24%),
        radial-gradient(circle at bottom left, rgba(74, 214, 195, 0.12), transparent 26%),
        linear-gradient(160deg, #08111f 0%, #0b1630 46%, #101a35 100%);
}

a {
    color: var(--accent);
    text-decoration-color: rgba(108, 183, 255, 0.45);
    transition: color 150ms ease, text-decoration-color 150ms ease;
}

a:hover {
    color: #9ed2ff;
    text-decoration-color: rgba(158, 210, 255, 0.85);
}

a:focus-visible,
button:focus-visible,
.nav-link:focus-visible {
    outline: 2px solid var(--focus);
    outline-offset: 2px;
    border-radius: 4px;
}

.skip-link {
    position: absolute;
    left: -999px;
    top: 8px;
    z-index: 20;
    background: #fff;
    color: #000;
    padding: 6px 10px;
}

.skip-link:focus {
    left: 8px;
}

.app-shell {
    display: grid;
    grid-template-columns: 250px 1fr;
    min-height: 100vh;
}

.sidebar {
    border-right: 1px solid var(--border);
    background:
        linear-gradient(180deg, rgba(25, 41, 70, 0.96) 0%, rgba(12, 21, 39, 0.96) 100%);
    box-shadow: inset -1px 0 0 rgba(255, 255, 255, 0.03);
    padding: 12px;
    position: sticky;
    top: 0;
    height: 100vh;
    overflow-y: auto;
}

.brand {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 1.05rem;
    margin: 0 0 12px;
    color: #f4f7ff;
    letter-spacing: 0.01em;
}

.brand-logo {
    width: 26px;
    height: 26px;
    border-radius: 4px;
    object-fit: cover;
    flex: 0 0 auto;
    box-shadow: 0 0 0 1px rgba(255, 255, 255, 0.08), 0 8px 20px rgba(0, 0, 0, 0.22);
}

.nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 4px;
}

.nav-link {
    display: block;
    text-decoration: none;
    color: var(--text);
    padding: 8px 10px;
    border-radius: 6px;
    border: 1px solid transparent;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.01), rgba(255, 255, 255, 0));
    transition: background 150ms ease, border-color 150ms ease, transform 150ms ease, box-shadow 150ms ease;
}

.nav-link:hover {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.14), rgba(140, 123, 255, 0.08));
    border-color: rgba(108, 183, 255, 0.35);
    box-shadow: 0 6px 18px rgba(6, 14, 30, 0.18);
    transform: translateX(1px);
}

.nav-link.active {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.22), rgba(140, 123, 255, 0.14));
    border-color: rgba(140, 123, 255, 0.45);
    box-shadow: inset 3px 0 0 var(--accent-warm), 0 8px 18px rgba(10, 21, 42, 0.22);
}

.main {
    padding: 12px 16px;
    overflow-x: auto;
    overflow-y: auto;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.015) 0%, rgba(255, 255, 255, 0) 100%);
    display: flex;
    flex-direction: column;
    height: 100vh;
}

section {
    display: flex;
    flex-direction: column;
    min-height: 0;
    flex: 1;
}

.page-header {
    margin: 0 0 10px;
    flex: 0 0 auto;
}

.page-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #f3f7ff;
    letter-spacing: 0.01em;
}

.page-header h2::after {
    content: '';
    display: block;
    width: 56px;
    height: 3px;
    margin-top: 6px;
    border-radius: 999px;
    background: linear-gradient(90deg, var(--accent), var(--accent-strong), var(--accent-warm));
}

h3 {
    margin: 0 0 8px;
    font-size: 1rem;
    color: #f4f7ff;
}

p {
    margin: 0 0 8px;
}

.muted {
    color: var(--muted);
    font-size: 0.92rem;
}

.section-gap {
    margin-top: 12px;
}

.stats-grid,
.card-grid,
.split-grid {
    display: grid;
    gap: 10px;
}

.stats-grid {
    grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
}

.card-grid {
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
}

.split-grid {
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
}

.stack {
    display: grid;
    gap: 8px;
}

.card {
    background:
        linear-gradient(180deg, rgba(255, 255, 255, 0.03) 0%, rgba(255, 255, 255, 0) 100%),
        linear-gradient(180deg, var(--surface) 0%, #0f1a31 100%);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 10px;
    box-shadow: var(--shadow-card);
}

.stat-card .value {
    font-size: 1.3rem;
    font-weight: 650;
    margin: 2px 0 4px;
    color: #f7faff;
}

.tight-list {
    margin: 0;
    padding-left: 16px;
    display: grid;
    gap: 5px;
}

.table-wrap {
    overflow: auto;
    border: 1px solid var(--border);
    border-radius: 8px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.02), rgba(255, 255, 255, 0));
    box-shadow: var(--shadow-soft);
}

table {
    width: 100%;
    border-collapse: collapse;
    min-width: 720px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.02), rgba(255, 255, 255, 0)), var(--surface);
}

th,
td {
    padding: 8px;
    text-align: left;
    border-bottom: 1px solid var(--border);
    vertical-align: top;
}

th {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.14), rgba(140, 123, 255, 0.08)), var(--surface-soft);
    font-size: 0.92rem;
    color: #edf4ff;
}

.sr-only {
    position: absolute;
    width: 1px;
    height: 1px;
    margin: -1px;
    border: 0;
    clip: rect(0, 0, 0, 0);
    overflow: hidden;
}

.sound-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
}

.sound-filter-wrap {
    margin: 0 0 10px;
}

.sound-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.sound-button {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 12px 14px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    border: 1px solid var(--border);
    border-radius: 6px;
    color: var(--text);
    cursor: pointer;
    font-size: 0.95rem;
    text-align: left;
    transition: all 150ms ease;
}

.sound-button:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.sound-button:active {
    transform: scale(0.98);
}

.sound-button.playing {
    background: linear-gradient(135deg, rgba(74, 214, 195, 0.22), rgba(108, 183, 255, 0.18)), #173a60;
    border-color: rgba(74, 214, 195, 0.55);
    color: #eefdff;
}

.sound-button.paused {
    background: linear-gradient(135deg, rgba(140, 123, 255, 0.2), rgba(108, 183, 255, 0.12)), #2b3657;
    border-color: rgba(140, 123, 255, 0.42);
    color: #d9e3ff;
}

.sound-name {
    font-weight: 500;
}

.play-indicator {
    margin-left: 12px;
    font-size: 0.85rem;
    color: var(--muted);
    flex: 0 0 auto;
}

.sound-button.playing .play-indicator {
    color: var(--accent);
}

.sound-button.paused .play-indicator {
    color: #b0c4e8;
}

.illustration-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
}

.illustration-filter-wrap {
    margin: 0 0 10px;
}

.illustration-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.illustration-link {
    width: 100%;
    text-align: left;
    padding: 10px 12px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.95rem;
}

.illustration-link:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.illustration-overlay {
    position: fixed;
    inset: 0;
    z-index: 1200;
    background: linear-gradient(180deg, rgba(9, 15, 28, 0.98), rgba(7, 13, 25, 0.98));
    display: grid;
    grid-template-rows: auto 1fr;
    gap: 8px;
    padding: 10px;
}

.illustration-close {
    justify-self: end;
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.26), rgba(140, 123, 255, 0.16)), #243557;
    color: var(--text);
    border: 1px solid rgba(108, 183, 255, 0.42);
    border-radius: 6px;
    padding: 7px 12px;
    cursor: pointer;
}

.illustration-stage {
    min-height: 0;
    display: flex;
    align-items: center;
    justify-content: center;
}

.illustration-image {
    width: 100%;
    height: 100%;
    object-fit: contain;
}

.gallery-page {
    display: flex;
    flex-direction: column;
}

.gallery-browser {
    display: flex;
    flex-direction: column;
}

.gallery-filter-wrap {
    margin: 0 0 10px;
    position: sticky;
    top: 0;
    z-index: 15;
    padding: 4px 0 8px;
    flex: 0 0 auto;
    background: linear-gradient(180deg, rgba(7, 17, 31, 0.98), rgba(7, 17, 31, 0.9));
}

.gallery-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.gallery-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(210px, 1fr));
    gap: 10px;
}

.gallery-item {
    min-width: 0;
}

.gallery-thumb-button {
    width: 100%;
    display: grid;
    gap: 8px;
    text-align: left;
    padding: 10px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 8px;
    cursor: pointer;
    transition: border-color 150ms ease, box-shadow 150ms ease, background 150ms ease;
}

.gallery-thumb-button:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.gallery-thumb-image {
    width: 100%;
    aspect-ratio: 16 / 10;
    object-fit: cover;
    border-radius: 6px;
    background: #0b1324;
}

.gallery-thumb-title {
    font-size: 0.92rem;
    color: #e8f1ff;
}

.gallery-lightbox {
    position: fixed;
    inset: 0;
    z-index: 1300;
    background: linear-gradient(180deg, rgba(9, 15, 28, 0.985), rgba(7, 13, 25, 0.985));
    display: grid;
    grid-template-rows: auto 1fr;
    gap: 8px;
    padding: 10px;
}

.gallery-lightbox-toolbar {
    display: flex;
    justify-content: flex-end;
    gap: 8px;
}

.gallery-lightbox-close {
    justify-self: end;
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.26), rgba(140, 123, 255, 0.16)), #243557;
    color: var(--text);
    border: 1px solid rgba(108, 183, 255, 0.42);
    border-radius: 6px;
    padding: 7px 12px;
    cursor: pointer;
}

.gallery-lightbox-stage {
    min-height: 0;
    display: flex;
    position: relative;
    align-items: center;
    justify-content: center;
    padding: 6px;
    touch-action: pan-y;
}

.gallery-lightbox-stage-nav {
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    width: 44px;
    height: 44px;
    border-radius: 999px;
    border: 1px solid rgba(108, 183, 255, 0.45);
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.28), rgba(140, 123, 255, 0.16)), #203150;
    color: #f1f6ff;
    font-size: 1.4rem;
    line-height: 1;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 10px 24px rgba(4, 10, 24, 0.34);
}

.gallery-lightbox-stage-nav:hover {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.38), rgba(255, 124, 168, 0.16)), #2b3f67;
}

.gallery-lightbox-stage-nav-left {
    left: 12px;
}

.gallery-lightbox-stage-nav-right {
    right: 12px;
}

.gallery-lightbox-image {
    max-width: 100%;
    max-height: 100%;
    width: auto;
    height: auto;
    object-fit: contain;
}

.syllogism-grid {
    display: grid;
    gap: 10px;
    grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
}

.syllogism-form {
    display: grid;
    grid-template-columns: 1fr auto;
    gap: 8px;
    margin-bottom: 10px;
}

.syllogism-input {
    width: 100%;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 8px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.syllogism-input:disabled {
    opacity: 0.65;
}

.syllogism-button,
.syllogism-remove,
.syllogism-clear {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.18), rgba(140, 123, 255, 0.12)), #203150;
    color: var(--text);
    border: 1px solid rgba(108, 183, 255, 0.38);
    border-radius: 6px;
    padding: 8px 10px;
    cursor: pointer;
    box-shadow: 0 8px 18px rgba(6, 14, 30, 0.16);
}

.syllogism-button:hover,
.syllogism-remove:hover,
.syllogism-clear:hover {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.26), rgba(255, 124, 168, 0.14)), #2b3f67;
}

.syllogism-button:disabled,
.syllogism-clear:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.syllogism-list {
    margin: 0;
    padding-left: 18px;
    display: grid;
    gap: 8px;
}

.syllogism-item {
    display: grid;
    grid-template-columns: 1fr auto;
    gap: 8px;
    align-items: start;
}

.syllogism-conclusion {
    border: 1px solid var(--border);
    background: #18233b;
    border-radius: 8px;
    padding: 10px;
}

.syllogism-actions {
    margin-top: 10px;
    display: flex;
    justify-content: flex-end;
}

.syllogism-title-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
}

.syllogism-filter-wrap {
    margin: 0 0 10px;
}

.syllogism-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.syllogism-title-button {
    width: 100%;
    text-align: left;
    padding: 10px 12px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    cursor: pointer;
}

.syllogism-title-button:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.syllogism-view {
    max-width: 1100px;
}

.syllogism-subheading {
    margin: 0 0 6px;
    font-size: 0.95rem;
}

.syllogism-premise-list,
.syllogism-note-list {
    margin: 0;
    padding-left: 18px;
    display: grid;
    gap: 6px;
}

.syllogism-view-actions {
    margin-top: 12px;
    display: flex;
    justify-content: flex-end;
}

.contradiction-title-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
}

.contradiction-filter-wrap {
    margin: 0 0 10px;
}

.contradiction-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.contradiction-title-button {
    width: 100%;
    text-align: left;
    padding: 10px 12px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    cursor: pointer;
}

.contradiction-title-button:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.contradiction-view {
    max-width: 1100px;
}

.contradiction-subheading {
    margin: 0 0 6px;
    font-size: 0.95rem;
}

.contradiction-view-actions {
    margin-top: 12px;
    display: flex;
    justify-content: flex-end;
}

.docs-layout {
    display: grid;
    grid-template-columns: minmax(260px, 340px) 1fr;
    gap: 10px;
    align-items: stretch;
    min-height: 0;
    flex: 1;
}

.docs-sidebar {
    display: flex;
    flex-direction: column;
    min-height: 0;
    height: 100%;
    max-height: calc(100vh - 100px);
    overflow: hidden;
}

.docs-filter-wrap {
    margin: 0 0 10px;
    flex: 0 0 auto;
}

.docs-filter {
    width: 100%;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.docs-title-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
    overflow-y: auto;
    min-height: 0;
    flex: 1;
}

.docs-title-link {
    display: grid;
    gap: 4px;
    text-decoration: none;
    padding: 10px 12px;
    border-radius: 6px;
    border: 1px solid var(--border);
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
}

.docs-title-link:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.docs-title-link.active {
    border-color: rgba(140, 123, 255, 0.48);
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.2), rgba(140, 123, 255, 0.14));
    box-shadow: inset 3px 0 0 var(--accent-warm), 0 8px 18px rgba(10, 21, 42, 0.22);
}

.docs-title {
    font-weight: 620;
}

.docs-summary {
    font-size: 0.9rem;
    color: var(--muted);
}

.docs-viewer {
    min-height: 0;
    max-height: calc(100vh - 100px);
    overflow-y: auto;
    min-width: 0;
}

.docs-viewer-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
    margin-bottom: 10px;
}

.docs-raw-link {
    font-size: 0.9rem;
    white-space: nowrap;
}

.docs-markdown {
    color: #eef4ff;
    line-height: 1.58;
    font-size: 1.02rem;
}

.docs-markdown h1,
.docs-markdown h2,
.docs-markdown h3,
.docs-markdown h4 {
    margin: 1.1em 0 0.45em;
    line-height: 1.3;
    color: #f7faff;
}

.docs-markdown h1 {
    font-size: 2.15rem;
    margin-top: 0;
    letter-spacing: 0.01em;
}

.docs-markdown h2 {
    font-size: 1.35rem;
    border-top: 1px solid rgba(255, 255, 255, 0.15);
    padding-top: 0.65em;
}

.docs-markdown p,
.docs-markdown ul,
.docs-markdown ol,
.docs-markdown blockquote,
.docs-markdown pre,
.docs-markdown table {
    margin: 0 0 0.95em;
}

.docs-markdown ul,
.docs-markdown ol {
    padding-left: 1.35em;
}

.docs-markdown li {
    margin: 0.36em 0;
}

.docs-markdown hr {
    border: none;
    border-top: 1px solid rgba(255, 255, 255, 0.18);
    margin: 1.15em 0;
}

.docs-markdown blockquote {
    border-left: 3px solid rgba(108, 183, 255, 0.5);
    padding-left: 12px;
    color: #d3def4;
}

.docs-markdown code {
    background: rgba(108, 183, 255, 0.12);
    border: 1px solid rgba(108, 183, 255, 0.26);
    border-radius: 4px;
    padding: 1px 4px;
    font-size: 0.94em;
}

.docs-markdown pre {
    background: #10192f;
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 10px;
    overflow: auto;
}

.docs-markdown pre code {
    background: transparent;
    border: none;
    padding: 0;
}

.docs-markdown .katex-display {
    margin: 0.95em 0;
    overflow-x: auto;
    overflow-y: hidden;
    padding: 0.08em 0.04em;
}

.docs-markdown .katex {
    font-size: 1.06em;
}

.docs-markdown table {
    width: 100%;
    border-collapse: collapse;
}

.docs-markdown th,
.docs-markdown td {
    border: 1px solid var(--border);
    padding: 6px 7px;
}

.bible-verse-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
}

.bible-verse-filter-wrap {
    margin: 0 0 10px;
}

.bible-verse-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.bible-verse-button {
    width: 100%;
    text-align: left;
    display: grid;
    gap: 4px;
    padding: 10px 12px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    cursor: pointer;
}

.bible-verse-button:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.bible-verse-ref {
    font-weight: 650;
}

.bible-verse-summary {
    color: var(--muted);
    font-size: 0.92rem;
}

.bible-verse-overlay {
    position: fixed;
    inset: 0;
    z-index: 1250;
    background: linear-gradient(180deg, rgba(9, 15, 28, 0.98), rgba(7, 13, 25, 0.98));
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 12px;
}

.bible-verse-dialog {
    width: min(1000px, 100%);
    max-height: 100%;
    overflow: auto;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.07), rgba(255, 255, 255, 0)), #0f172b;
    border: 1px solid rgba(108, 183, 255, 0.28);
    border-radius: 10px;
    padding: 12px;
    box-shadow: 0 22px 44px rgba(0, 0, 0, 0.34);
}

.bible-verse-close {
    justify-self: end;
    display: block;
    margin-left: auto;
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.26), rgba(140, 123, 255, 0.16)), #243557;
    color: var(--text);
    border: 1px solid rgba(108, 183, 255, 0.42);
    border-radius: 6px;
    padding: 7px 12px;
    cursor: pointer;
}

.bible-verse-open-ref {
    margin: 8px 0 6px;
}

.bible-verse-open-summary {
    margin: 0 0 8px;
    color: #b8d4ff;
    font-weight: 600;
}

.bible-verse-open-text {
    margin: 0;
    white-space: pre-wrap;
}

.prophecy-form {
    display: grid;
    gap: 10px;
    max-width: 900px;
}

.prophecy-field {
    display: grid;
    gap: 6px;
}

.prophecy-label {
    font-size: 0.92rem;
    color: var(--muted);
    font-weight: 600;
}

.prophecy-input {
    width: 100%;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.prophecy-textarea {
    resize: vertical;
    min-height: 84px;
}

.prophecy-actions {
    display: flex;
    justify-content: flex-end;
    gap: 8px;
    flex-wrap: wrap;
    margin-top: 14px;
}

.prophecy-button,
.prophecy-reset {
    background: #203150;
    color: var(--text);
    border: 1px solid #395385;
    border-radius: 6px;
    padding: 9px 12px;
    cursor: pointer;
}

.prophecy-button:hover,
.prophecy-reset:hover {
    background: #2b3f67;
}

.prophecy-button:disabled {
    opacity: 0.55;
    cursor: not-allowed;
}

.prophecy-scorecard {
    margin-top: 14px;
}

@media (max-width: 900px) {
    .app-shell {
        grid-template-columns: 1fr;
    }

    .sidebar {
        height: auto;
        position: static;
        border-right: none;
        border-bottom: 1px solid var(--border);
    }

    .nav-list {
        grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    }

    table {
        min-width: 600px;
    }

    .docs-layout {
        grid-template-columns: 1fr;
    }

    .docs-sidebar {
        height: auto;
        flex-direction: column;
    }

    .docs-title-list {
        max-height: 350px;
        overflow-y: auto;
    }
}

@media (max-width: 700px) {
    :root {
        font-size: 14px;
    }

    .sidebar {
        padding: 10px;
    }

    .brand {
        margin-bottom: 10px;
    }

    .brand-logo {
        width: 24px;
        height: 24px;
    }

    .nav-list {
        display: flex;
        flex-wrap: nowrap;
        overflow-x: auto;
        gap: 6px;
        padding-bottom: 4px;
        scrollbar-width: thin;
    }

    .nav-list li {
        flex: 0 0 auto;
    }

    .nav-link {
        padding: 7px 9px;
        white-space: nowrap;
    }

    .main {
        padding: 10px 12px 14px;
    }

    .page-header h2 {
        font-size: 1rem;
    }

    .card-grid,
    .split-grid {
        grid-template-columns: 1fr;
    }

    .syllogism-grid {
        grid-template-columns: 1fr;
    }

    .stats-grid {
        grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    }

    .card {
        padding: 9px;
    }

    .table-wrap {
        border-radius: 6px;
    }

    table {
        min-width: 560px;
    }

    th,
    td {
        padding: 7px;
    }

    .illustration-overlay {
        padding: 8px;
    }

    .gallery-lightbox {
        padding: 8px;
    }

    .gallery-lightbox-stage-nav {
        width: 40px;
        height: 40px;
    }

    .syllogism-form {
        grid-template-columns: 1fr;
    }

    .bible-verse-overlay {
        padding: 8px;
    }

    .bible-verse-dialog {
        padding: 10px;
    }

    .prophecy-actions {
        justify-content: stretch;
    }

    .docs-viewer-header {
        flex-direction: column;
        align-items: flex-start;
    }

    .prophecy-button,
    .prophecy-reset {
        width: 100%;
    }
}

@media (max-width: 480px) {
    .app-shell {
        min-height: auto;
    }

    .sidebar {
        padding: 8px;
    }

    .brand {
        font-size: 1rem;
    }

    .brand-logo {
        width: 22px;
        height: 22px;
    }

    .nav-link {
        padding: 6px 8px;
    }

    .main {
        padding: 8px 10px 12px;
    }

    .page-header {
        margin-bottom: 8px;
    }

    h3 {
        font-size: 0.96rem;
    }

    .muted {
        font-size: 0.88rem;
    }

    .stats-grid {
        grid-template-columns: 1fr;
    }

    .stat-card .value {
        font-size: 1.15rem;
    }

    .tight-list {
        padding-left: 14px;
    }

    table {
        min-width: 500px;
    }

    .illustration-link {
        padding: 9px 10px;
    }

    .illustration-close {
        padding: 6px 10px;
    }

    .gallery-lightbox-close {
        padding: 6px 10px;
    }

    .gallery-lightbox-stage-nav {
        width: 36px;
        height: 36px;
        font-size: 1.2rem;
    }

    .gallery-lightbox-stage-nav-left {
        left: 8px;
    }

    .gallery-lightbox-stage-nav-right {
        right: 8px;
    }

    .syllogism-item {
        grid-template-columns: 1fr;
    }

    .syllogism-actions {
        justify-content: stretch;
    }

    .syllogism-clear {
        width: 100%;
    }
}

/* ── Christian Quiz ─────────────────────────────────────────────────────── */

.quiz-wrap {
    display: flex;
    flex-direction: column;
    gap: 10px;
    max-width: 720px;
}

.quiz-setup {
    max-width: 720px;
    display: flex;
    flex-direction: column;
    gap: 14px;
}

.quiz-setup-copy {
    margin: 0;
    color: var(--muted);
}

.quiz-size-control {
    display: grid;
    gap: 8px;
}

.quiz-book-filter {
    display: grid;
    gap: 6px;
}

.quiz-book-filter-label {
    margin: 0;
    font-size: 0.92rem;
}

.quiz-book-options {
    display: flex;
    flex-wrap: wrap;
    gap: 10px 16px;
}

.quiz-book-option {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    font-size: 0.92rem;
}

.quiz-book-option input:disabled + span {
    opacity: 0.75;
}

.quiz-size-label {
    font-size: 0.95rem;
}

.quiz-size-input {
    width: 100%;
    accent-color: var(--accent);
}

.quiz-size-range {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
}

.quiz-meta {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 6px;
    font-size: 0.9rem;
}

.quiz-progress {
    color: var(--muted);
}

.quiz-running-score {
    color: var(--accent);
    font-size: 0.92rem;
}

.quiz-progress-bar {
    height: 5px;
    border-radius: 999px;
    background: var(--surface-strong);
    overflow: hidden;
}

.quiz-progress-fill {
    height: 100%;
    border-radius: 999px;
    background: linear-gradient(90deg, var(--accent), var(--accent-strong));
    transition: width 350ms ease;
}

.quiz-card {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.quiz-reference {
    margin: 0;
    font-size: 0.82rem;
    letter-spacing: 0.02em;
    text-transform: uppercase;
}

.quiz-reference-hidden {
    visibility: hidden;
}

.quiz-question {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 600;
    color: #f0f6ff;
    line-height: 1.5;
}

.quiz-answers {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 7px;
}

.quiz-answer-btn {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
    width: 100%;
    padding: 11px 14px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.05), rgba(255, 255, 255, 0)), var(--surface);
    border: 1px solid var(--border);
    border-radius: 7px;
    color: var(--text);
    cursor: pointer;
    font-size: 0.95rem;
    text-align: left;
    transition: background 140ms ease, border-color 140ms ease, transform 120ms ease;
}

.quiz-answer-btn:not(:disabled):hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.13), rgba(140, 123, 255, 0.07)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.44);
    transform: translateX(2px);
}

.quiz-answer-btn:disabled {
    cursor: default;
    opacity: 0.55;
}

.quiz-answer-selected {
    opacity: 1 !important;
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.18), rgba(140, 123, 255, 0.12)), #1d3258 !important;
}

.quiz-pts-border-4.quiz-answer-selected { border-color: #4ad6c3 !important; }
.quiz-pts-border-3.quiz-answer-selected { border-color: #6cb7ff !important; }
.quiz-pts-border-2.quiz-answer-selected { border-color: #b3a4ff !important; }
.quiz-pts-border-1.quiz-answer-selected { border-color: #ffb870 !important; }
.quiz-pts-border-0.quiz-answer-selected { border-color: #ff7ca8 !important; }

.quiz-answer-revealed {
    opacity: 0.55;
}

.quiz-answer-text {
    flex: 1;
    line-height: 1.45;
}

.quiz-pts-badge {
    flex: 0 0 auto;
    font-size: 0.8rem;
    font-weight: 700;
    padding: 2px 8px;
    border-radius: 999px;
    white-space: nowrap;
}

.quiz-pts-4 { color: #0d1a2e; background: #4ad6c3; }
.quiz-pts-3 { color: #0d1a2e; background: #6cb7ff; }
.quiz-pts-2 { color: #0d1a2e; background: #b3a4ff; }
.quiz-pts-1 { color: #0d1a2e; background: #ffb870; }
.quiz-pts-0 { color: #0d1a2e; background: #ff7ca8; }

.quiz-answered-feedback {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 10px;
    padding-top: 4px;
    border-top: 1px solid var(--border-soft);
}

.quiz-pts-earned {
    font-size: 1.05rem;
    font-weight: 700;
    padding: 4px 12px;
    border-radius: 999px;
}

.quiz-next-btn {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.22), rgba(140, 123, 255, 0.14)), #203150;
    color: var(--text);
    border: 1px solid rgba(108, 183, 255, 0.42);
    border-radius: 7px;
    padding: 10px 20px;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 140ms ease, transform 120ms ease;
}

.quiz-next-btn:hover {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.32), rgba(255, 124, 168, 0.16)), #2b3f67;
    transform: translateY(-1px);
}

/* ── Results screen ── */

.quiz-results {
    max-width: 720px;
    display: flex;
    flex-direction: column;
    gap: 14px;
}

.quiz-results-label {
    margin: 0;
    font-size: 1.5rem;
    color: var(--accent);
    letter-spacing: 0.01em;
}

.quiz-results-score {
    margin: 0;
    font-size: 1rem;
    color: var(--text);
}

.quiz-results-bar-wrap {
    height: 8px;
    border-radius: 999px;
    background: var(--surface-strong);
    overflow: hidden;
}

.quiz-results-bar-fill {
    height: 100%;
    border-radius: 999px;
    background: linear-gradient(90deg, var(--accent-teal), var(--accent), var(--accent-strong));
    transition: width 600ms ease;
}

.quiz-results-breakdown {
    display: grid;
    gap: 8px;
    border-top: 1px solid var(--border-soft);
    padding-top: 10px;
}

.quiz-result-row {
    display: grid;
    grid-template-columns: 1fr 2fr auto;
    gap: 10px;
    align-items: start;
    padding: 8px 10px;
    background: var(--surface-soft);
    border: 1px solid var(--border);
    border-radius: 6px;
    font-size: 0.88rem;
}

.quiz-result-q {
    color: var(--muted);
    font-style: italic;
}

.quiz-result-a {
    color: var(--text);
}

.quiz-result-pts {
    font-weight: 700;
    font-size: 0.82rem;
    padding: 2px 8px;
    border-radius: 999px;
    white-space: nowrap;
    align-self: start;
}

@media (max-width: 600px) {
    .quiz-result-row {
        grid-template-columns: 1fr;
    }

    .quiz-answered-feedback {
        flex-direction: column;
        align-items: stretch;
    }

    .quiz-next-btn {
        width: 100%;
        text-align: center;
    }
}

:root {
    color-scheme: dark;
    --bg: #07111f;
    --bg-soft: #0d1730;
    --surface: #111d35;
    --surface-soft: #192946;
    --surface-strong: #22365b;
    --text: #edf3ff;
    --muted: #aab7d1;
    --accent: #6cb7ff;
    --accent-strong: #8c7bff;
    --accent-warm: #ff7ca8;
    --accent-teal: #4ad6c3;
    --border: #31486f;
    --border-soft: rgba(124, 160, 255, 0.18);
    --focus: #9fd0ff;
    --shadow-soft: 0 10px 30px rgba(2, 8, 20, 0.28);
    --shadow-card: 0 14px 34px rgba(4, 10, 24, 0.3);
    font-family: Inter, Segoe UI, Roboto, Arial, sans-serif;
    font-size: 15px;
    line-height: 1.4;
    font-weight: 400;
}

* {
    box-sizing: border-box;
}

body {
    margin: 0;
    min-height: 100vh;
    color: var(--text);
    background:
        radial-gradient(circle at top left, rgba(108, 183, 255, 0.18), transparent 28%),
        radial-gradient(circle at top right, rgba(140, 123, 255, 0.16), transparent 24%),
        radial-gradient(circle at bottom left, rgba(74, 214, 195, 0.12), transparent 26%),
        linear-gradient(160deg, #08111f 0%, #0b1630 46%, #101a35 100%);
}

a {
    color: var(--accent);
    text-decoration-color: rgba(108, 183, 255, 0.45);
    transition: color 150ms ease, text-decoration-color 150ms ease;
}

a:hover {
    color: #9ed2ff;
    text-decoration-color: rgba(158, 210, 255, 0.85);
}

a:focus-visible,
button:focus-visible,
.nav-link:focus-visible {
    outline: 2px solid var(--focus);
    outline-offset: 2px;
    border-radius: 4px;
}

.skip-link {
    position: absolute;
    left: -999px;
    top: 8px;
    z-index: 20;
    background: #fff;
    color: #000;
    padding: 6px 10px;
}

.skip-link:focus {
    left: 8px;
}

.app-shell {
    display: grid;
    grid-template-columns: 250px 1fr;
    min-height: 100vh;
}

.sidebar {
    border-right: 1px solid var(--border);
    background:
        linear-gradient(180deg, rgba(25, 41, 70, 0.96) 0%, rgba(12, 21, 39, 0.96) 100%);
    box-shadow: inset -1px 0 0 rgba(255, 255, 255, 0.03);
    padding: 12px;
    position: sticky;
    top: 0;
    height: 100vh;
    overflow-y: auto;
}

.brand {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 1.05rem;
    margin: 0 0 12px;
    color: #f4f7ff;
    letter-spacing: 0.01em;
}

.brand-logo {
    width: 26px;
    height: 26px;
    border-radius: 4px;
    object-fit: cover;
    flex: 0 0 auto;
    box-shadow: 0 0 0 1px rgba(255, 255, 255, 0.08), 0 8px 20px rgba(0, 0, 0, 0.22);
}

.nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 4px;
}

.nav-link {
    display: block;
    text-decoration: none;
    color: var(--text);
    padding: 8px 10px;
    border-radius: 6px;
    border: 1px solid transparent;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.01), rgba(255, 255, 255, 0));
    transition: background 150ms ease, border-color 150ms ease, transform 150ms ease, box-shadow 150ms ease;
}

.nav-link:hover {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.14), rgba(140, 123, 255, 0.08));
    border-color: rgba(108, 183, 255, 0.35);
    box-shadow: 0 6px 18px rgba(6, 14, 30, 0.18);
    transform: translateX(1px);
}

.nav-link.active {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.22), rgba(140, 123, 255, 0.14));
    border-color: rgba(140, 123, 255, 0.45);
    box-shadow: inset 3px 0 0 var(--accent-warm), 0 8px 18px rgba(10, 21, 42, 0.22);
}

.main {
    padding: 12px 16px;
    overflow-x: auto;
    overflow-y: auto;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.015) 0%, rgba(255, 255, 255, 0) 100%);
    display: flex;
    flex-direction: column;
    height: 100vh;
}

section {
    display: flex;
    flex-direction: column;
    min-height: 0;
    flex: 1;
}

.page-header {
    margin: 0 0 10px;
    flex: 0 0 auto;
}

.page-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #f3f7ff;
    letter-spacing: 0.01em;
}

.page-header h2::after {
    content: '';
    display: block;
    width: 56px;
    height: 3px;
    margin-top: 6px;
    border-radius: 999px;
    background: linear-gradient(90deg, var(--accent), var(--accent-strong), var(--accent-warm));
}

h3 {
    margin: 0 0 8px;
    font-size: 1rem;
    color: #f4f7ff;
}

p {
    margin: 0 0 8px;
}

.muted {
    color: var(--muted);
    font-size: 0.92rem;
}

.section-gap {
    margin-top: 12px;
}

.stats-grid,
.card-grid,
.split-grid {
    display: grid;
    gap: 10px;
}

.stats-grid {
    grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
}

.card-grid {
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
}

.split-grid {
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
}

.stack {
    display: grid;
    gap: 8px;
}

.card {
    background:
        linear-gradient(180deg, rgba(255, 255, 255, 0.03) 0%, rgba(255, 255, 255, 0) 100%),
        linear-gradient(180deg, var(--surface) 0%, #0f1a31 100%);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 10px;
    box-shadow: var(--shadow-card);
}

.stat-card .value {
    font-size: 1.3rem;
    font-weight: 650;
    margin: 2px 0 4px;
    color: #f7faff;
}

.tight-list {
    margin: 0;
    padding-left: 16px;
    display: grid;
    gap: 5px;
}

.table-wrap {
    overflow: auto;
    border: 1px solid var(--border);
    border-radius: 8px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.02), rgba(255, 255, 255, 0));
    box-shadow: var(--shadow-soft);
}

table {
    width: 100%;
    border-collapse: collapse;
    min-width: 720px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.02), rgba(255, 255, 255, 0)), var(--surface);
}

th,
td {
    padding: 8px;
    text-align: left;
    border-bottom: 1px solid var(--border);
    vertical-align: top;
}

th {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.14), rgba(140, 123, 255, 0.08)), var(--surface-soft);
    font-size: 0.92rem;
    color: #edf4ff;
}

.sr-only {
    position: absolute;
    width: 1px;
    height: 1px;
    margin: -1px;
    border: 0;
    clip: rect(0, 0, 0, 0);
    overflow: hidden;
}

.sound-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
}

.sound-filter-wrap {
    margin: 0 0 10px;
}

.sound-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.sound-button {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 12px 14px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    border: 1px solid var(--border);
    border-radius: 6px;
    color: var(--text);
    cursor: pointer;
    font-size: 0.95rem;
    text-align: left;
    transition: all 150ms ease;
}

.sound-button:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.sound-button:active {
    transform: scale(0.98);
}

.sound-button.playing {
    background: linear-gradient(135deg, rgba(74, 214, 195, 0.22), rgba(108, 183, 255, 0.18)), #173a60;
    border-color: rgba(74, 214, 195, 0.55);
    color: #eefdff;
}

.sound-button.paused {
    background: linear-gradient(135deg, rgba(140, 123, 255, 0.2), rgba(108, 183, 255, 0.12)), #2b3657;
    border-color: rgba(140, 123, 255, 0.42);
    color: #d9e3ff;
}

.sound-name {
    font-weight: 500;
}

.play-indicator {
    margin-left: 12px;
    font-size: 0.85rem;
    color: var(--muted);
    flex: 0 0 auto;
}

.sound-button.playing .play-indicator {
    color: var(--accent);
}

.sound-button.paused .play-indicator {
    color: #b0c4e8;
}

.illustration-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
}

.illustration-filter-wrap {
    margin: 0 0 10px;
}

.illustration-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.illustration-link {
    width: 100%;
    text-align: left;
    padding: 10px 12px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.95rem;
}

.illustration-link:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.illustration-overlay {
    position: fixed;
    inset: 0;
    z-index: 1200;
    background: linear-gradient(180deg, rgba(9, 15, 28, 0.98), rgba(7, 13, 25, 0.98));
    display: grid;
    grid-template-rows: auto 1fr;
    gap: 8px;
    padding: 10px;
}

.illustration-close {
    justify-self: end;
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.26), rgba(140, 123, 255, 0.16)), #243557;
    color: var(--text);
    border: 1px solid rgba(108, 183, 255, 0.42);
    border-radius: 6px;
    padding: 7px 12px;
    cursor: pointer;
}

.illustration-stage {
    min-height: 0;
    display: flex;
    align-items: center;
    justify-content: center;
}

.illustration-image {
    width: 100%;
    height: 100%;
    object-fit: contain;
}

.gallery-page {
    display: flex;
    flex-direction: column;
}

.gallery-browser {
    display: flex;
    flex-direction: column;
}

.gallery-filter-wrap {
    margin: 0 0 10px;
    position: sticky;
    top: 0;
    z-index: 15;
    padding: 4px 0 8px;
    flex: 0 0 auto;
    background: linear-gradient(180deg, rgba(7, 17, 31, 0.98), rgba(7, 17, 31, 0.9));
}

.gallery-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.gallery-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(210px, 1fr));
    gap: 10px;
}

.gallery-item {
    min-width: 0;
}

.gallery-thumb-button {
    width: 100%;
    display: grid;
    gap: 8px;
    text-align: left;
    padding: 10px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 8px;
    cursor: pointer;
    transition: border-color 150ms ease, box-shadow 150ms ease, background 150ms ease;
}

.gallery-thumb-button:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.gallery-thumb-image {
    width: 100%;
    aspect-ratio: 16 / 10;
    object-fit: cover;
    border-radius: 6px;
    background: #0b1324;
}

.gallery-thumb-title {
    font-size: 0.92rem;
    color: #e8f1ff;
}

.gallery-lightbox {
    position: fixed;
    inset: 0;
    z-index: 1300;
    background: linear-gradient(180deg, rgba(9, 15, 28, 0.985), rgba(7, 13, 25, 0.985));
    display: grid;
    grid-template-rows: auto 1fr;
    gap: 8px;
    padding: 10px;
}

.gallery-lightbox-toolbar {
    display: flex;
    justify-content: flex-end;
    gap: 8px;
}

.gallery-lightbox-close {
    justify-self: end;
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.26), rgba(140, 123, 255, 0.16)), #243557;
    color: var(--text);
    border: 1px solid rgba(108, 183, 255, 0.42);
    border-radius: 6px;
    padding: 7px 12px;
    cursor: pointer;
}

.gallery-lightbox-stage {
    min-height: 0;
    display: flex;
    position: relative;
    align-items: center;
    justify-content: center;
    padding: 6px;
    touch-action: pan-y;
}

.gallery-lightbox-stage-nav {
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    width: 44px;
    height: 44px;
    border-radius: 999px;
    border: 1px solid rgba(108, 183, 255, 0.45);
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.28), rgba(140, 123, 255, 0.16)), #203150;
    color: #f1f6ff;
    font-size: 1.4rem;
    line-height: 1;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 10px 24px rgba(4, 10, 24, 0.34);
}

.gallery-lightbox-stage-nav:hover {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.38), rgba(255, 124, 168, 0.16)), #2b3f67;
}

.gallery-lightbox-stage-nav-left {
    left: 12px;
}

.gallery-lightbox-stage-nav-right {
    right: 12px;
}

.gallery-lightbox-image {
    max-width: 100%;
    max-height: 100%;
    width: auto;
    height: auto;
    object-fit: contain;
}

.syllogism-grid {
    display: grid;
    gap: 10px;
    grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
}

.syllogism-form {
    display: grid;
    grid-template-columns: 1fr auto;
    gap: 8px;
    margin-bottom: 10px;
}

.syllogism-input {
    width: 100%;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 8px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.syllogism-input:disabled {
    opacity: 0.65;
}

.syllogism-button,
.syllogism-remove,
.syllogism-clear {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.18), rgba(140, 123, 255, 0.12)), #203150;
    color: var(--text);
    border: 1px solid rgba(108, 183, 255, 0.38);
    border-radius: 6px;
    padding: 8px 10px;
    cursor: pointer;
    box-shadow: 0 8px 18px rgba(6, 14, 30, 0.16);
}

.syllogism-button:hover,
.syllogism-remove:hover,
.syllogism-clear:hover {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.26), rgba(255, 124, 168, 0.14)), #2b3f67;
}

.syllogism-button:disabled,
.syllogism-clear:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.syllogism-list {
    margin: 0;
    padding-left: 18px;
    display: grid;
    gap: 8px;
}

.syllogism-item {
    display: grid;
    grid-template-columns: 1fr auto;
    gap: 8px;
    align-items: start;
}

.syllogism-conclusion {
    border: 1px solid var(--border);
    background: #18233b;
    border-radius: 8px;
    padding: 10px;
}

.syllogism-actions {
    margin-top: 10px;
    display: flex;
    justify-content: flex-end;
}

.syllogism-title-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
}

.syllogism-filter-wrap {
    margin: 0 0 10px;
    position: sticky;
    top: 0;
    z-index: 15;
    padding: 4px 0 8px;
    flex: 0 0 auto;
    background: linear-gradient(180deg, rgba(7, 17, 31, 0.98), rgba(7, 17, 31, 0.9));
}

.syllogism-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.syllogism-title-button {
    width: 100%;
    text-align: left;
    padding: 10px 12px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    cursor: pointer;
}

.syllogism-title-button:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.syllogism-view {
    max-width: 1100px;
}

.syllogism-subheading {
    margin: 0 0 6px;
    font-size: 0.95rem;
}

.syllogism-premise-list,
.syllogism-note-list {
    margin: 0;
    padding-left: 18px;
    display: grid;
    gap: 6px;
}

.syllogism-view-actions {
    margin-top: 12px;
    display: flex;
    justify-content: flex-end;
}

.contradiction-title-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
}

.contradiction-filter-wrap {
    margin: 0 0 10px;
}

.contradiction-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.contradiction-title-button {
    width: 100%;
    text-align: left;
    padding: 10px 12px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    cursor: pointer;
}

.contradiction-title-button:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.contradiction-view {
    max-width: 1100px;
}

.contradiction-subheading {
    margin: 0 0 6px;
    font-size: 0.95rem;
}

.contradiction-view-actions {
    margin-top: 12px;
    display: flex;
    justify-content: flex-end;
}

.docs-layout {
    display: grid;
    grid-template-columns: minmax(260px, 340px) 1fr;
    gap: 10px;
    align-items: stretch;
    min-height: 0;
    flex: 1;
}

.docs-sidebar {
    display: flex;
    flex-direction: column;
    min-height: 0;
    height: 100%;
    max-height: calc(100vh - 100px);
    overflow: hidden;
}

.docs-filter-wrap {
    margin: 0 0 10px;
    flex: 0 0 auto;
}

.docs-filter {
    width: 100%;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.docs-title-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
    overflow-y: auto;
    min-height: 0;
    flex: 1;
}

.docs-title-link {
    display: grid;
    gap: 4px;
    text-decoration: none;
    padding: 10px 12px;
    border-radius: 6px;
    border: 1px solid var(--border);
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
}

.docs-title-link:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.docs-title-link.active {
    border-color: rgba(140, 123, 255, 0.48);
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.2), rgba(140, 123, 255, 0.14));
    box-shadow: inset 3px 0 0 var(--accent-warm), 0 8px 18px rgba(10, 21, 42, 0.22);
}

.docs-title {
    font-weight: 620;
}

.docs-summary {
    font-size: 0.9rem;
    color: var(--muted);
}

.docs-viewer {
    min-height: 0;
    max-height: calc(100vh - 100px);
    overflow-y: auto;
    min-width: 0;
}

.docs-viewer-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
    margin-bottom: 10px;
}

.docs-raw-link {
    font-size: 0.9rem;
    white-space: nowrap;
}

.docs-markdown {
    color: #eef4ff;
    line-height: 1.58;
    font-size: 1.02rem;
}

.docs-markdown h1,
.docs-markdown h2,
.docs-markdown h3,
.docs-markdown h4 {
    margin: 1.1em 0 0.45em;
    line-height: 1.3;
    color: #f7faff;
}

.docs-markdown h1 {
    font-size: 2.15rem;
    margin-top: 0;
    letter-spacing: 0.01em;
}

.docs-markdown h2 {
    font-size: 1.35rem;
    border-top: 1px solid rgba(255, 255, 255, 0.15);
    padding-top: 0.65em;
}

.docs-markdown p,
.docs-markdown ul,
.docs-markdown ol,
.docs-markdown blockquote,
.docs-markdown pre,
.docs-markdown table {
    margin: 0 0 0.95em;
}

.docs-markdown ul,
.docs-markdown ol {
    padding-left: 1.35em;
}

.docs-markdown li {
    margin: 0.36em 0;
}

.docs-markdown hr {
    border: none;
    border-top: 1px solid rgba(255, 255, 255, 0.18);
    margin: 1.15em 0;
}

.docs-markdown blockquote {
    border-left: 3px solid rgba(108, 183, 255, 0.5);
    padding-left: 12px;
    color: #d3def4;
}

.docs-markdown code {
    background: rgba(108, 183, 255, 0.12);
    border: 1px solid rgba(108, 183, 255, 0.26);
    border-radius: 4px;
    padding: 1px 4px;
    font-size: 0.94em;
}

.docs-markdown pre {
    background: #10192f;
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 10px;
    overflow: auto;
}

.docs-markdown pre code {
    background: transparent;
    border: none;
    padding: 0;
}

.docs-markdown .katex-display {
    margin: 0.95em 0;
    overflow-x: auto;
    overflow-y: hidden;
    padding: 0.08em 0.04em;
}

.docs-markdown .katex {
    font-size: 1.06em;
}

.docs-markdown table {
    width: 100%;
    border-collapse: collapse;
}

.docs-markdown th,
.docs-markdown td {
    border: 1px solid var(--border);
    padding: 6px 7px;
}

.bible-verse-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 8px;
}

.bible-verse-filter-wrap {
    margin: 0 0 10px;
}

.bible-verse-filter {
    width: 100%;
    max-width: 560px;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.bible-verse-button {
    width: 100%;
    text-align: left;
    display: grid;
    gap: 4px;
    padding: 10px 12px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.06), rgba(255, 255, 255, 0)), var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    cursor: pointer;
}

.bible-verse-button:hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.12), rgba(140, 123, 255, 0.06)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.42);
    box-shadow: 0 10px 22px rgba(6, 14, 28, 0.18);
}

.bible-verse-ref {
    font-weight: 650;
}

.bible-verse-summary {
    color: var(--muted);
    font-size: 0.92rem;
}

.bible-verse-overlay {
    position: fixed;
    inset: 0;
    z-index: 1250;
    background: linear-gradient(180deg, rgba(9, 15, 28, 0.98), rgba(7, 13, 25, 0.98));
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 12px;
}

.bible-verse-dialog {
    width: min(1000px, 100%);
    max-height: 100%;
    overflow: auto;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.07), rgba(255, 255, 255, 0)), #0f172b;
    border: 1px solid rgba(108, 183, 255, 0.28);
    border-radius: 10px;
    padding: 12px;
    box-shadow: 0 22px 44px rgba(0, 0, 0, 0.34);
}

.bible-verse-close {
    justify-self: end;
    display: block;
    margin-left: auto;
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.26), rgba(140, 123, 255, 0.16)), #243557;
    color: var(--text);
    border: 1px solid rgba(108, 183, 255, 0.42);
    border-radius: 6px;
    padding: 7px 12px;
    cursor: pointer;
}

.bible-verse-open-ref {
    margin: 8px 0 6px;
}

.bible-verse-open-summary {
    margin: 0 0 8px;
    color: #b8d4ff;
    font-weight: 600;
}

.bible-verse-open-text {
    margin: 0;
    white-space: pre-wrap;
}

.prophecy-form {
    display: grid;
    gap: 10px;
    max-width: 900px;
}

.prophecy-field {
    display: grid;
    gap: 6px;
}

.prophecy-label {
    font-size: 0.92rem;
    color: var(--muted);
    font-weight: 600;
}

.prophecy-input {
    width: 100%;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.035), rgba(255, 255, 255, 0)), #0f1628;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 9px 10px;
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

.prophecy-textarea {
    resize: vertical;
    min-height: 84px;
}

.prophecy-actions {
    display: flex;
    justify-content: flex-end;
    gap: 8px;
    flex-wrap: wrap;
    margin-top: 14px;
}

.prophecy-button,
.prophecy-reset {
    background: #203150;
    color: var(--text);
    border: 1px solid #395385;
    border-radius: 6px;
    padding: 9px 12px;
    cursor: pointer;
}

.prophecy-button:hover,
.prophecy-reset:hover {
    background: #2b3f67;
}

.prophecy-button:disabled {
    opacity: 0.55;
    cursor: not-allowed;
}

.prophecy-scorecard {
    margin-top: 14px;
}

@media (max-width: 900px) {
    .app-shell {
        grid-template-columns: 1fr;
    }

    .sidebar {
        height: auto;
        position: static;
        border-right: none;
        border-bottom: 1px solid var(--border);
    }

    .nav-list {
        grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    }

    table {
        min-width: 600px;
    }

    .docs-layout {
        grid-template-columns: 1fr;
    }

    .docs-sidebar {
        height: auto;
        flex-direction: column;
    }

    .docs-title-list {
        max-height: 350px;
        overflow-y: auto;
    }
}

@media (max-width: 700px) {
    :root {
        font-size: 14px;
    }

    .sidebar {
        padding: 10px;
    }

    .brand {
        margin-bottom: 10px;
    }

    .brand-logo {
        width: 24px;
        height: 24px;
    }

    .nav-list {
        display: flex;
        flex-wrap: nowrap;
        overflow-x: auto;
        gap: 6px;
        padding-bottom: 4px;
        scrollbar-width: thin;
    }

    .nav-list li {
        flex: 0 0 auto;
    }

    .nav-link {
        padding: 7px 9px;
        white-space: nowrap;
    }

    .main {
        padding: 10px 12px 14px;
    }

    .page-header h2 {
        font-size: 1rem;
    }

    .card-grid,
    .split-grid {
        grid-template-columns: 1fr;
    }

    .syllogism-grid {
        grid-template-columns: 1fr;
    }

    .stats-grid {
        grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    }

    .card {
        padding: 9px;
    }

    .table-wrap {
        border-radius: 6px;
    }

    table {
        min-width: 560px;
    }

    th,
    td {
        padding: 7px;
    }

    .illustration-overlay {
        padding: 8px;
    }

    .gallery-lightbox {
        padding: 8px;
    }

    .gallery-lightbox-stage-nav {
        width: 40px;
        height: 40px;
    }

    .syllogism-form {
        grid-template-columns: 1fr;
    }

    .bible-verse-overlay {
        padding: 8px;
    }

    .bible-verse-dialog {
        padding: 10px;
    }

    .prophecy-actions {
        justify-content: stretch;
    }

    .docs-viewer-header {
        flex-direction: column;
        align-items: flex-start;
    }

    .prophecy-button,
    .prophecy-reset {
        width: 100%;
    }
}

@media (max-width: 480px) {
    .app-shell {
        min-height: auto;
    }

    .sidebar {
        padding: 8px;
    }

    .brand {
        font-size: 1rem;
    }

    .brand-logo {
        width: 22px;
        height: 22px;
    }

    .nav-link {
        padding: 6px 8px;
    }

    .main {
        padding: 8px 10px 12px;
    }

    .page-header {
        margin-bottom: 8px;
    }

    h3 {
        font-size: 0.96rem;
    }

    .muted {
        font-size: 0.88rem;
    }

    .stats-grid {
        grid-template-columns: 1fr;
    }

    .stat-card .value {
        font-size: 1.15rem;
    }

    .tight-list {
        padding-left: 14px;
    }

    table {
        min-width: 500px;
    }

    .illustration-link {
        padding: 9px 10px;
    }

    .illustration-close {
        padding: 6px 10px;
    }

    .gallery-lightbox-close {
        padding: 6px 10px;
    }

    .gallery-lightbox-stage-nav {
        width: 36px;
        height: 36px;
        font-size: 1.2rem;
    }

    .gallery-lightbox-stage-nav-left {
        left: 8px;
    }

    .gallery-lightbox-stage-nav-right {
        right: 8px;
    }

    .syllogism-item {
        grid-template-columns: 1fr;
    }

    .syllogism-actions {
        justify-content: stretch;
    }

    .syllogism-clear {
        width: 100%;
    }
}

/* ── Christian Quiz ─────────────────────────────────────────────────────── */

.quiz-wrap {
    display: flex;
    flex-direction: column;
    gap: 10px;
    max-width: 720px;
}

.quiz-setup {
    max-width: 720px;
    display: flex;
    flex-direction: column;
    gap: 14px;
}

.quiz-setup-copy {
    margin: 0;
    color: var(--muted);
}

.quiz-size-control {
    display: grid;
    gap: 8px;
}

.quiz-book-filter {
    display: grid;
    gap: 6px;
}

.quiz-book-filter-label {
    margin: 0;
    font-size: 0.92rem;
}

.quiz-book-options {
    display: flex;
    flex-wrap: wrap;
    gap: 10px 16px;
}

.quiz-book-option {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    font-size: 0.92rem;
}

.quiz-book-option input:disabled + span {
    opacity: 0.75;
}

.quiz-size-label {
    font-size: 0.95rem;
}

.quiz-size-input {
    width: 100%;
    accent-color: var(--accent);
}

.quiz-size-range {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
}

.quiz-meta {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 6px;
    font-size: 0.9rem;
}

.quiz-progress {
    color: var(--muted);
}

.quiz-running-score {
    color: var(--accent);
    font-size: 0.92rem;
}

.quiz-progress-bar {
    height: 5px;
    border-radius: 999px;
    background: var(--surface-strong);
    overflow: hidden;
}

.quiz-progress-fill {
    height: 100%;
    border-radius: 999px;
    background: linear-gradient(90deg, var(--accent), var(--accent-strong));
    transition: width 350ms ease;
}

.quiz-card {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.quiz-reference {
    margin: 0;
    font-size: 0.82rem;
    letter-spacing: 0.02em;
    text-transform: uppercase;
}

.quiz-reference-hidden {
    visibility: hidden;
}

.quiz-question {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 600;
    color: #f0f6ff;
    line-height: 1.5;
}

.quiz-answers {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    gap: 7px;
}

.quiz-answer-btn {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
    width: 100%;
    padding: 11px 14px;
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.05), rgba(255, 255, 255, 0)), var(--surface);
    border: 1px solid var(--border);
    border-radius: 7px;
    color: var(--text);
    cursor: pointer;
    font-size: 0.95rem;
    text-align: left;
    transition: background 140ms ease, border-color 140ms ease, transform 120ms ease;
}

.quiz-answer-btn:not(:disabled):hover {
    background: linear-gradient(180deg, rgba(108, 183, 255, 0.13), rgba(140, 123, 255, 0.07)), var(--surface-soft);
    border-color: rgba(108, 183, 255, 0.44);
    transform: translateX(2px);
}

.quiz-answer-btn:disabled {
    cursor: default;
    opacity: 0.55;
}

.quiz-answer-selected {
    opacity: 1 !important;
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.18), rgba(140, 123, 255, 0.12)), #1d3258 !important;
}

.quiz-pts-border-4.quiz-answer-selected { border-color: #4ad6c3 !important; }
.quiz-pts-border-3.quiz-answer-selected { border-color: #6cb7ff !important; }
.quiz-pts-border-2.quiz-answer-selected { border-color: #b3a4ff !important; }
.quiz-pts-border-1.quiz-answer-selected { border-color: #ffb870 !important; }
.quiz-pts-border-0.quiz-answer-selected { border-color: #ff7ca8 !important; }

.quiz-answer-revealed {
    opacity: 0.55;
}

.quiz-answer-text {
    flex: 1;
    line-height: 1.45;
}

.quiz-pts-badge {
    flex: 0 0 auto;
    font-size: 0.8rem;
    font-weight: 700;
    padding: 2px 8px;
    border-radius: 999px;
    white-space: nowrap;
}

.quiz-pts-4 { color: #0d1a2e; background: #4ad6c3; }
.quiz-pts-3 { color: #0d1a2e; background: #6cb7ff; }
.quiz-pts-2 { color: #0d1a2e; background: #b3a4ff; }
.quiz-pts-1 { color: #0d1a2e; background: #ffb870; }
.quiz-pts-0 { color: #0d1a2e; background: #ff7ca8; }

.quiz-answered-feedback {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 10px;
    padding-top: 4px;
    border-top: 1px solid var(--border-soft);
}

.quiz-pts-earned {
    font-size: 1.05rem;
    font-weight: 700;
    padding: 4px 12px;
    border-radius: 999px;
}

.quiz-next-btn {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.22), rgba(140, 123, 255, 0.14)), #203150;
    color: var(--text);
    border: 1px solid rgba(108, 183, 255, 0.42);
    border-radius: 7px;
    padding: 10px 20px;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 140ms ease, transform 120ms ease;
}

.quiz-next-btn:hover {
    background: linear-gradient(135deg, rgba(108, 183, 255, 0.32), rgba(255, 124, 168, 0.16)), #2b3f67;
    transform: translateY(-1px);
}

/* ── Results screen ── */

.quiz-results {
    max-width: 720px;
    display: flex;
    flex-direction: column;
    gap: 14px;
}

.quiz-results-label {
    margin: 0;
    font-size: 1.5rem;
    color: var(--accent);
    letter-spacing: 0.01em;
}

.quiz-results-score {
    margin: 0;
    font-size: 1rem;
    color: var(--text);
}

.quiz-results-bar-wrap {
    height: 8px;
    border-radius: 999px;
    background: var(--surface-strong);
    overflow: hidden;
}

.quiz-results-bar-fill {
    height: 100%;
    border-radius: 999px;
    background: linear-gradient(90deg, var(--accent-teal), var(--accent), var(--accent-strong));
    transition: width 600ms ease;
}

.quiz-results-breakdown {
    display: grid;
    gap: 8px;
    border-top: 1px solid var(--border-soft);
    padding-top: 10px;
}

.quiz-result-row {
    display: grid;
    grid-template-columns: 1fr 2fr auto;
    gap: 10px;
    align-items: start;
    padding: 8px 10px;
    background: var(--surface-soft);
    border: 1px solid var(--border);
    border-radius: 6px;
    font-size: 0.88rem;
}

.quiz-result-q {
    color: var(--muted);
    font-style: italic;
}

.quiz-result-a {
    color: var(--text);
}

.quiz-result-pts {
    font-weight: 700;
    font-size: 0.82rem;
    padding: 2px 8px;
    border-radius: 999px;
    white-space: nowrap;
    align-self: start;
}

@media (max-width: 600px) {
    .quiz-result-row {
        grid-template-columns: 1fr;
    }

    .quiz-answered-feedback {
        flex-direction: column;
        align-items: stretch;
    }

    .quiz-next-btn {
        width: 100%;
        text-align: center;
    }
}
